var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 지금 그의 이름은 속삭이는 자, <color=#ffd34c>네헤모트</color>.","JPN":"そう。今の彼の名前は囁く者、<color=#ffd34c>ネヘモト</color>。","ENG":"Correct. His new name is <color=#ffd34c>Nehemoth</color> the Whisperer.","TWN":"沒錯，他現在的名字是私語者 <color=#ffd34c>貝赫莫特</color>。"},"stage":{"bg":"MAINSTREAM_7130013","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가짜 구세주, 실패한 구원자라고도 불리는……","JPN":"偽の救世主、失敗した救世主とも呼ばれる……","ENG":"Also known as the False Savior, the Fallen Shepherd…","TWN":"也有人稱他是假救世主，失敗的救贖者……"},"stage":{"bg":"MAINSTREAM_7130013","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"클리포트의 마왕들 중 하나다.","JPN":"クリフォトの魔王の一人だ。","ENG":"He's one of the Demon Lords of Qliphoth.","TWN":"是逆卡巴拉的魔王之一。"},"stage":{"bg":"MAINSTREAM_7130013","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……라더니!","JPN":"……って言ってたけど！","ENG":"... That’s what I heard!","TWN":"……就說這樣！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 클리포트의 마왕들이란 게 대체 뭔데? 실패한 구원자는 또 뭐고?","JPN":"クリフォトの魔王って何？　失敗した救世主って何？","ENG":"So who are these Demon Lords of Qliphoth? Who is the Fallen Shepherd?","TWN":"所以逆卡巴拉的魔王是什麼？失敗的救贖者又是什麼？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"결국 아무것도 알려 준 게 없잖아!","JPN":"結局、肝心なことは何も教えてくれてないじゃん！","ENG":"So in the end, they told me nothing!","TWN":"根本都沒解釋啊！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러더니 부사장님은 의뢰가 들어왔으니 일이나 하라고 이렇게 보내버리고.","JPN":"なのに副社長ったら、依頼が入ったから仕事しろって言ってくるし。","ENG":"Then the Vice President sent me away on a mission.","TWN":"後來副總又說什麼有工作進來，就叫我先去做事，然後我就在這裡啦！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으으, 생각했더니 또 열 받아!","JPN":"うぐぐ……思い出したらまたイライラしてきた！","ENG":"Urgh! It makes me angry all over again!","TWN":"可惡，想起來還是覺得上火！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 진정하세요, 미나 양. 다른 손님들이 여길 노려보고 있거든요.","JPN":"ハハ。落ち着いてください、ミナさん。周りのお客さんに見られてますよ。","ENG":"Haha, calm down, Mina. Other customers are glaring at you.","TWN":"哈哈，米娜，你冷靜點，大家都在看我們欸。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……선배, 선배는 혹시 뭔가 들은 거 있어?","JPN":"……先輩、先輩はもしかして何か聞いてない？","ENG":"Shiyoon, do you know anything about this?","TWN":"……前輩，你有聽說什麼嗎？"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요…… 지난 주에 시작한 모바일 게임에 마왕인가 뭔가가 나왔던 것 같긴 한데 말이죠.","JPN":"そうですね……先週始まったモバイルゲームの中に\\n魔王とか何かが出てきた気がしますが。","ENG":"Um... I did see a demon lord in the mobile game I started playing last week.","TWN":"這個嘛……我是有聽說，上個禮拜出的新手遊裡面是有魔王沒錯啦。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누가 게임 이야기 물어봤어? 자꾸 그런 식으로 말 돌리기만 할 거야?","JPN":"誰もゲームの話なんか聞いてないよ？　とぼけないでよ！","ENG":"I’m not talking about a game! Stop changing the subject.","TWN":"誰在跟你講遊戲的事啦！你又在給我轉移話題對不對！"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"정말 모르는 일이라서요, 어쩔 수 없죠.","JPN":"本当にわからないので、しょうがないですよ。","ENG":"I can’t help it. I really don’t know anything.","TWN":"沒辦法，我就真的不知道嘛～"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오히려 긍정적으로 생각해 보세요. 스승님이 최소한 입을 열긴 했잖아요.","JPN":"こういう時はポジティブに考えてみてください。あの師匠が一応ヒントをくれたんですから。","ENG":"Well, look on the bright side. At least the Master brought up the topic.","TWN":"我們換個角度想，起碼師父還有對你開金口。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 그것만 해도 거의 10년이나 걸렸다고요.","JPN":"僕なんてそれすら10年ぐらいかかったんですからね。","ENG":"It took me almost ten years for that.","TWN":"我可是花了快10年的時間，才等到她開金口欸。"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배도 소대장 상대하느라 고생이 참 많았겠다…….","JPN":"先輩も小隊長を相手に大変だね……","ENG":"It must have been very hard for you, dealing with the Commander all those years...","TWN":"前輩要和小隊長打交道應該也很辛苦吧……"},"stage":{"bg":"CAFE_STREGA","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};